First, we need to set up our project structure. We'll have:

- MongoDB: For storing all the juicy data about rooms and bookings.
- Express.js: As our robust backend server.
- React: For the frontend where users can interact with the system.
- Node.js: To run everything smoothly.

Let's start with the backend (Express.js + MongoDB).

### Backend Setup

1. **Initialize Project:**

```bash
mkdir RoomManagementSystem
cd RoomManagementSystem
npm init -y
```

2. **Install Dependencies:**

```bash
npm install express mongoose body-parser cors
npm install --save-dev nodemon
```

3. **Create `server.js`:**

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/roommanagement', {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

const db = mongoose.connection;
db.on('error', console.error.bind(console, 'connection error:'));
db.once('open', () => {
    console.log("We're connected to MongoDB!");
});

// Define Room Schema
const RoomSchema = new mongoose.Schema({
    name: String,
    capacity: Number,
    booked: { type: Boolean, default: false }
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.send(rooms);
});

app.post('/rooms', async (req, res) => {
    const room = new Room(req.body);
    await room.save();
    res.send(room);
});

app.put('/rooms/:id', async (req, res) => {
    const room = await Room.findByIdAndUpdate(req.params.id, req.body, { new: true });
    res.send(room);
});

app.delete('/rooms/:id', async (req, res) => {
    await Room.findByIdAndDelete(req.params.id);
    res.send({ message: "Room deleted" });
});

// Start Server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

